// pages/QuizPage.jsx — Professional MCQ Quiz Experience
import React, { useState, useEffect, useRef, useCallback } from "react";
import { Link } from "react-router-dom";
import { useQuiz } from "../hooks/useQuiz";

// ─────────────────────────────────────────────
// Constants
// ─────────────────────────────────────────────
const OPTION_KEYS = ["A", "B", "C", "D"];
const DIFFICULTY_META = {
  easy:   { label: "Easy",   color: "#4ade80", bg: "rgba(74,222,128,0.10)",  border: "rgba(74,222,128,0.25)"  },
  medium: { label: "Medium", color: "#fbbf24", bg: "rgba(251,191,36,0.10)",  border: "rgba(251,191,36,0.25)"  },
  hard:   { label: "Hard",   color: "#f87171", bg: "rgba(248,113,113,0.10)", border: "rgba(248,113,113,0.25)" },
};
const OPTION_ACCENT = {
  A: { idle: "rgba(99,102,241,0.12)",  active: "rgba(99,102,241,0.28)",  border: "#6366f1", text: "#a5b4fc" },
  B: { idle: "rgba(14,165,233,0.12)",  active: "rgba(14,165,233,0.28)",  border: "#0ea5e9", text: "#7dd3fc" },
  C: { idle: "rgba(168,85,247,0.12)",  active: "rgba(168,85,247,0.28)",  border: "#a855f7", text: "#d8b4fe" },
  D: { idle: "rgba(236,72,153,0.12)",  active: "rgba(236,72,153,0.28)",  border: "#ec4899", text: "#f9a8d4" },
};
const POPULAR_TOPICS = [
  "Profit & Loss","Time & Work","Speed, Distance & Time",
  "Percentages","Simple & Compound Interest","Ratios & Proportions",
  "Number Systems","Averages","Permutation & Combination","Probability",
];

// ─────────────────────────────────────────────
// Sub-components
// ─────────────────────────────────────────────

function TopicSelector({ onStart }) {
  const [topic, setTopic]   = useState("");
  const [count, setCount]   = useState(10);
  const inputRef            = useRef(null);

  useEffect(() => { inputRef.current?.focus(); }, []);

  const handleStart = () => {
    const t = topic.trim();
    if (!t) return;
    onStart(t, count);
  };

  return (
    <div className="quiz-setup">
      {/* Hero */}
      <div className="setup-hero">
        <div className="quiz-badge">APTITUDE QUIZ</div>
        <h1 className="setup-title">Test Your Skills</h1>
        <p className="setup-sub">Pick a topic, set your question count, and challenge yourself</p>
      </div>

      {/* Input card */}
      <div className="setup-card">
        <label className="field-label">Topic</label>
        <input
          ref={inputRef}
          className="topic-input"
          value={topic}
          onChange={e => setTopic(e.target.value)}
          onKeyDown={e => e.key === "Enter" && handleStart()}
          placeholder="e.g. Profit & Loss, Percentages…"
        />

        {/* Popular chips */}
        <div className="chips-row">
          {POPULAR_TOPICS.map(t => (
            <button key={t} className={`chip ${topic === t ? "chip-active" : ""}`} onClick={() => setTopic(t)}>
              {t}
            </button>
          ))}
        </div>

        {/* Count selector */}
        <label className="field-label" style={{ marginTop: "1.5rem" }}>
          Questions — <span style={{ color: "#a5b4fc" }}>{count}</span>
        </label>
        <div className="count-row">
          {[5, 10, 15, 20].map(n => (
            <button
              key={n}
              className={`count-btn ${count === n ? "count-active" : ""}`}
              onClick={() => setCount(n)}
            >
              {n}
            </button>
          ))}
        </div>

        <button
          className="start-btn"
          onClick={handleStart}
          disabled={!topic.trim()}
        >
          Start Quiz →
        </button>
      </div>
    </div>
  );
}

// ── Loading screen ──────────────────────────
function QuizLoader({ topic }) {
  return (
    <div className="quiz-loader">
      <div className="loader-ring" />
      <p className="loader-text">Generating quiz for</p>
      <p className="loader-topic">"{topic}"</p>
    </div>
  );
}

// ── Single question card ────────────────────
function QuestionCard({ question, index, total, onAnswer, userAnswer }) {
  const diff = DIFFICULTY_META[question.difficulty] || DIFFICULTY_META.medium;

  return (
    <div className="q-card">
      {/* Header row */}
      <div className="q-header">
        <div className="q-counter">
          <span className="q-num">{index + 1}</span>
          <span className="q-of">/ {total}</span>
        </div>
        <span className="q-diff-badge" style={{ color: diff.color, background: diff.bg, border: `1px solid ${diff.border}` }}>
          {diff.label}
        </span>
      </div>

      {/* Progress bar */}
      <div className="q-progress-track">
        <div className="q-progress-fill" style={{ width: `${((index + 1) / total) * 100}%` }} />
      </div>

      {/* Question text */}
      <p className="q-text">{question.question}</p>

      {/* Options */}
      <div className="options-grid">
        {OPTION_KEYS.map(key => {
          const acc      = OPTION_ACCENT[key];
          const selected = userAnswer === key;
          const bg     = selected ? acc.active : acc.idle;
          const border = selected ? acc.border : "rgba(255,255,255,0.08)";
          const color  = selected ? acc.text   : "#94a3b8";
          const weight = selected ? "600"      : "400";

          return (
            <button
              key={key}
              className="option-btn"
              onClick={() => onAnswer(key)}
              style={{ background: bg, border: `1px solid ${border}`, color, fontWeight: weight }}
            >
              <span className="opt-key" style={{ color: acc.text }}>{key}</span>
              <span className="opt-text">{question.options[key]}</span>
            </button>
          );
        })}
      </div>
    </div>
  );
}

// ── Quiz runner ─────────────────────────────
function QuizRunner({ questions, topic, onRestart, onNewTopic }) {
  const [current,   setCurrent]  = useState(0);
  const [answers,   setAnswers]  = useState({});
  const [finished,  setFinished] = useState(false);
  const cardRef = useRef(null);

  const q = questions[current];

  const handleAnswer = useCallback((key) => {
    setAnswers(prev => ({ ...prev, [current]: key }));
  }, [current]);

  const handleSubmit = () => {
    if (current + 1 >= questions.length) {
      setFinished(true);
    } else {
      setCurrent(c => c + 1);
      cardRef.current?.scrollIntoView({ behavior: "smooth", block: "start" });
    }
  };

  // Results screen
  if (finished) {
    const score     = questions.filter((q, i) => answers[i] === q.correctAnswer).length;
    const pct       = Math.round((score / questions.length) * 100);
    const skipped   = questions.length - Object.keys(answers).length;
    const wrong     = Object.keys(answers).length - score;
    const grade     =
      pct >= 90 ? { label: "Excellent!", color: "#4ade80", emoji: "🏆" } :
      pct >= 70 ? { label: "Good Job!",  color: "#fbbf24", emoji: "🎯" } :
      pct >= 50 ? { label: "Keep Going", color: "#60a5fa", emoji: "📚" } :
                  { label: "More Practice!", color: "#f87171", emoji: "💪" };

    return (
      <div className="results-screen">
        <div className="results-card">
          <div className="results-emoji">{grade.emoji}</div>
          <h2 className="results-grade" style={{ color: grade.color }}>{grade.label}</h2>
          <p className="results-topic">{topic}</p>

          {/* Score ring */}
          <div className="score-ring-wrap">
            <svg viewBox="0 0 120 120" className="score-svg">
              <circle cx="60" cy="60" r="50" fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="10" />
              <circle
                cx="60" cy="60" r="50" fill="none"
                stroke={grade.color} strokeWidth="10"
                strokeDasharray={`${2 * Math.PI * 50}`}
                strokeDashoffset={`${2 * Math.PI * 50 * (1 - pct / 100)}`}
                strokeLinecap="round"
                transform="rotate(-90 60 60)"
                style={{ transition: "stroke-dashoffset 1s ease" }}
              />
            </svg>
            <div className="score-inner">
              <span className="score-pct">{pct}%</span>
              <span className="score-fraction">{score}/{questions.length}</span>
            </div>
          </div>

          {/* Stats row */}
          <div className="stats-row">
            <div className="stat-box" style={{ borderColor: "rgba(74,222,128,0.3)" }}>
              <span className="stat-num" style={{ color: "#4ade80" }}>{score}</span>
              <span className="stat-lbl">Correct</span>
            </div>
            <div className="stat-box" style={{ borderColor: "rgba(248,113,113,0.3)" }}>
              <span className="stat-num" style={{ color: "#f87171" }}>{wrong}</span>
              <span className="stat-lbl">Wrong</span>
            </div>
            <div className="stat-box" style={{ borderColor: "rgba(148,163,184,0.3)" }}>
              <span className="stat-num" style={{ color: "#94a3b8" }}>{skipped}</span>
              <span className="stat-lbl">Skipped</span>
            </div>
          </div>

          {/* Per-question review */}
          <div className="review-list">
            <p className="review-title">Question Review</p>
            {questions.map((q, i) => {
              const ans    = answers[i];
              const correct = ans === q.correctAnswer;
              const skipped = !ans;
              return (
                <div key={i} className="review-item">
                  <span className={`review-dot ${skipped ? "dot-skip" : correct ? "dot-ok" : "dot-wrong"}`} />
                  <span className="review-q">{i + 1}. {q.question}</span>
                  <span className="review-tag" style={{
                    color: skipped ? "#64748b" : correct ? "#4ade80" : "#f87171"
                  }}>
                    {skipped ? "–" : correct ? `✓ ${ans}` : `✗ ${ans} (${q.correctAnswer})`}
                  </span>
                </div>
              );
            })}
          </div>

          {/* Actions */}
          <div className="results-actions">
            <button className="btn-retake" onClick={onRestart}>Retake Quiz</button>
            <button className="btn-newtopic" onClick={onNewTopic}>New Topic</button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="quiz-runner" ref={cardRef}>
      {/* Top bar */}
      <div className="runner-topbar">
        <button className="topbar-back" onClick={onNewTopic}>← Topics</button>
        <span className="topbar-topic">{topic}</span>
        <span className="topbar-count">{Object.keys(answers).length}/{questions.length} answered</span>
      </div>

      <QuestionCard
        question={q}
        index={current}
        total={questions.length}
        onAnswer={handleAnswer}
        userAnswer={answers[current]}
      />

      {/* Single submit button */}
      <div className="action-bar">
        <button
          className="btn-submit"
          disabled={!answers[current]}
          onClick={handleSubmit}
        >
          {!answers[current]
            ? "Select an option"
            : current + 1 >= questions.length
            ? "Submit Quiz →"
            : "Submit →"}
        </button>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────
// Main page
// ─────────────────────────────────────────────
export default function QuizPage() {
  const { fetchQuiz, loading, error } = useQuiz();
  const [phase,     setPhase]     = useState("setup");   // setup | loading | quiz
  const [questions, setQuestions] = useState([]);
  const [activeTopic, setActiveTopic] = useState("");

  const handleStart = async (topic, count) => {
    setActiveTopic(topic);
    setPhase("loading");
    const qs = await fetchQuiz(topic, count);
    if (qs) {
      setQuestions(qs);
      setPhase("quiz");
    } else {
      setPhase("setup");
    }
  };

  const handleRestart = () => {
    setPhase("loading");
    fetchQuiz(activeTopic, questions.length).then(qs => {
      if (qs) { setQuestions(qs); setPhase("quiz"); }
      else setPhase("setup");
    });
  };

  return (
    <>
      <style>{QUIZ_STYLES}</style>
      <main className="quiz-page">
        {phase === "setup"   && <TopicSelector onStart={handleStart} />}
        {phase === "loading" && <QuizLoader topic={activeTopic} />}
        {error && phase === "setup" && (
          <div className="quiz-error">⚠️ {error}</div>
        )}
        {phase === "quiz" && questions.length > 0 && (
          <QuizRunner
            questions={questions}
            topic={activeTopic}
            onRestart={handleRestart}
            onNewTopic={() => setPhase("setup")}
          />
        )}

        <div style={{ textAlign: "center", marginTop: "2rem" }}>
          <Link to="/" className="back-home-link">← Back to Home</Link>
        </div>
      </main>
    </>
  );
}

